const recipes = $('Get Recipe From Mealie By Slug').all();

const mealPlanRecipes = recipes.map(item => {
  const recipe = item.json;
  return {
    recipeId: recipe.id,
    recipeIncrementQuantity: recipe.recipeServings ?? 1,
    recipeIngredients: (recipe.recipeIngredient ?? []).map(ing => ({
      quantity: ing.quantity ?? 0,
      unit: ing.unit ?? null,
      food: ing.food ?? null,
      referencedRecipe: ing.referencedRecipe ?? null,
      note: ing.note ?? "",
      display: ing.display ?? "",
      title: ing.title ?? null,
      originalText: ing.originalText ?? null,
      referenceId: ing.referenceId ?? null,
    }))
  };
});

return [{
  json: {
    recipes: mealPlanRecipes
  }
}];

const days = [];
const today = new Date();

for (let i = 0; i < 7; i++) {
  const date = new Date(today);
  date.setDate(today.getDate() + i);

  days.push({
    json: {
      date: date.toISOString().split("T")[0],
      dayOfWeek: date.toLocaleDateString("en-US", { weekday: "long" }),
    }
  });
}

return days;
